141â†’     */
142â†’    private static String getTagSlugFromEndpoint(final String endpoint) {
143â†’        if (TextUtils.isEmpty(endpoint)) {
144â†’            return "";
145â†’        }
146â†’
147â†’        // make sure passed endpoint is valid
148â†’        if (!endpoint.endsWith("/posts")) {
149â†’            return "";
150â†’        }
151â†’        int start = endpoint.indexOf("/read/tags/");
152â†’        if (start == -1) {
153â†’            return "";
154â†’        }
155â†’
156â†’        // skip "/read/tags/" then find the next "/"
157â†’        start += 11;
158â†’        int end = endpoint.indexOf("/", start);
159â†’        if (end == -1) {
160â†’            return "";
161â†’        }
162â†’
163â†’        return endpoint.substring(start, end);
164â†’    }
